import React from "react"
import { properties } from '../../properties/properties.js'


class CyberAdmin extends React.Component {

    constructor(props) {
        super(props);
        this.state = { screen: 0, result: []
        };
    }

    runMoveToAssign = (evt) => {

    }



    componentDidMount() {

        this.setState({screen: 0});

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');


        var backUrl = properties.backend + `cyberraptor/data`

        fetch(backUrl, {
          "method": "GET",
          headers: headers
        })
        .then(response => response.json())
        .then(response => {
            this.setState({result: response})
            this.setState({screen: 1})
        })
        .catch(err => {
          console.log(err);
        });

    }


    render() {


        var header = "Loading ..."
        var content = []

        if (this.state.screen == 1) {


            header = ""

            var HOTeams = this.state.result.HOTeams
            var team2 = []

            if (HOTeams.length > 0) {


                this.state.team.map(Record => team2.push(<option key={Record.name} value={Record.name}>{Record.name}</option>))

                content.push(<div style={{fontSize: "16px", color: "green", marginTop: "50px"}}>
                    <div><u><b>Please assign the following patients</b></u></div>
                    <div style={{marginTop: "15px"}}>*** NOTE - in some cases the lists may have doubled patients, so the total number may be smaller than the sum of the lists. ***</div>
                </div>)


                for (var key in HOTeams) {
                    var covidString = <font style={{color: "red", fontSize: "14px"}}><i></i></font>
                    if (HOTeams[key].COVID.length > 0) {
                        covidString = <font style={{color: "red", fontSize: "14px"}}><br></br><i>*** {HOTeams[key].COVID}</i></font>
                    }
                    var teamName = ""
                    teamName = "Sign out from " + HOTeams[key].team
                    if (HOTeams[key].Team === "Medicine X Robin") {
                        teamName = "**CrossCover signout from Eagle; Detailed sign out from Medicine X Robin"
                    }
                    var remainLocation = ""
                    try {
                    if (HOTeams[key].Location.length > 0) {
                        remainLocation = " (" + HOTeams[key].Location + ")"
                    } 
                    } catch (e) {}
                    content.push(<div style={{fontSize: "14px"}}><font style={{color: "#8B4513"}}><b>MRN: {HOTeams[key].MRN} {HOTeams[key].Name} {HOTeams[key].Age} {HOTeams[key].Sex} {remainLocation}</b></font><font style={{color: "#9B870C", fontSize: "14px"}}> - <u>{teamName}</u></font>{covidString}<br></br><font style={{color: 'blue'}}>{HOTeams[key].OneLiner ? HOTeams[key].OneLiner : ""}</font><div>move to <select id={"move_" + HOTeams[key].MRN}>{team2}</select> <button style={{marginLeft: '12px'}} onClick={this.runMoveToAssign} value={HOTeams[key].index}>submit</button></div><br></br></div>)
                }



            }





            content.push("Loaded")
        }


        return (
            <div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}
            </div>
        );


      }


}


export default CyberAdmin
